import axios from 'axios';

const API_BASE_URL = 'http://localhost:5033/api';

const api = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
    'Accept': 'application/json'
  }
});

api.interceptors.request.use(
  (config) => {
    const token = sessionStorage.getItem('token') || localStorage.getItem('token');
    if (token) {
      config.headers = config.headers || {};
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => Promise.reject(error)
);

api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401) {
      sessionStorage.clear();
      localStorage.clear();
    }
    return Promise.reject(error);
  }
);

export const getMongoId = (obj) => {
  if (!obj) return null;
  if (obj._id?.$oid) return obj._id.$oid;
  if (typeof obj._id === 'string' && /^[0-9a-f]{24}$/i.test(obj._id)) return obj._id;
  if (obj.id?.$oid) return obj.id.$oid;
  if (typeof obj.id === 'string' && /^[0-9a-f]{24}$/i.test(obj.id)) return obj.id;
  if (obj.Id?.$oid) return obj.Id.$oid;
  if (typeof obj.Id === 'string' && /^[0-9a-f]{24}$/i.test(obj.Id)) return obj.Id;
  if (typeof obj.mongoId === 'string' && /^[0-9a-f]{24}$/i.test(obj.mongoId)) return obj.mongoId;
  return null;
};

export const isValidMongoId = (id) => {
  return id && typeof id === 'string' && /^[0-9a-f]{24}$/i.test(id);
};

export const getUserIdFromToken = () => {
  const token = sessionStorage.getItem('token') || localStorage.getItem('token');
  if (!token) return null;
  try {
    const payload = JSON.parse(atob(token.split('.')[1]));
    return payload.nameid || payload['http://schemas.xmlsoap.org/ws/2005/05/identity/claims/nameidentifier'] || payload.sub || payload.userId || payload.id;
  } catch (error) {
    return null;
  }
};

export const mongoAuthAPI = {
  login: (email, password) => api.post('/mongo/auth/login', { email, password }),
  register: (fullName, email, mobile, password, gender = '') => api.post('/mongo/auth/register', { fullName, email, mobile, password, gender }),
  requestOtp: (mobile) => api.post('/mongo/auth/request-otp', { mobile }),
  verifyOtp: (mobile, otp) => api.post('/mongo/auth/verify-otp', { mobile, otp }),
  requestEmailOtp: (email) => api.post('/mongo/auth/request-email-otp', { email }),
  verifyEmailOtp: (email, otp) => api.post('/mongo/auth/verify-email-otp', { email, otp })
};

export const cartAPI = {
  view: (userId) => api.get(`/mongo/cart/user/${userId}`),
  add: (userId, data) => api.post(`/mongo/cart/user/${userId}/items`, { productId: String(data.productId), quantity: data.quantity || 1 }),
  update: (userId, productId, quantity) => api.put(`/mongo/cart/user/${userId}/items/${String(productId)}`, { quantity }),
  remove: (userId, productId) => api.delete(`/mongo/cart/user/${userId}/items/${String(productId)}`),
  clear: (userId) => api.delete(`/mongo/cart/user/${userId}`)
};

export const productsAPI = {
  getAll: () => api.get('/mongo/products'),
  search: (query) => api.get('/mongo/products/search', { params: { query: query || '' } }),
  getById: (id) => api.get(`/mongo/products/${id}`),
  suggest: (q) => api.get('/mongo/products/suggest', { params: { q } }),
  create: (productData) => api.post('/mongo/products', productData),
  update: (id, productData) => api.put(`/mongo/products/${id}`, productData),
  delete: (id) => api.delete(`/mongo/products/${id}`)
};

export const ordersAPI = {
  confirm: (shippingAddressId) => {
    if (!shippingAddressId || !isValidMongoId(shippingAddressId)) {
      return Promise.reject(new Error('Valid MongoDB Address ID required'));
    }
    return api.post('/mongo/order/confirm', { ShippingAddressId: shippingAddressId });
  },
  history: () => api.get('/mongo/order/history'),
  getById: (mongoId) => api.get(`/mongo/order/${mongoId}`),
  getByOrderNumber: (orderNumber) => api.get(`/mongo/order/order-number/${orderNumber}`),
  cancel: (mongoId) => api.post(`/mongo/order/${mongoId}/cancel`)
};

export const adminAPI = {
  getUsers: () => api.get('/mongo/admin/users'),
  getUserById: (mongoId) => api.get(`/mongo/admin/users/${mongoId}`),
  deleteUser: (mongoId) => api.delete(`/mongo/admin/users/${mongoId}`),
  getOrders: () => api.get('/mongo/admin/orders'),
  getOrderStats: () => api.get('/mongo/admin/order-stats'),
  updateOrderStatus: (orderId, statusData) => api.put(`/mongo/admin/orders/${orderId}/status`, statusData),
  getSalesReport: (startDate, endDate) => api.get('/mongo/admin/sales-report', { params: { startDate, endDate } }),
  getRevenue: (startDate, endDate) => api.get('/mongo/admin/revenue', { params: { startDate, endDate } }),
  getSalesByCategory: (startDate, endDate) => api.get('/mongo/admin/sales-by-category', { params: { startDate, endDate } }),
  getSalesByProduct: (startDate, endDate) => api.get('/mongo/admin/sales-by-product', { params: { startDate, endDate } }),
  getTopProducts: (limit = 10) => api.get('/mongo/admin/top-products', { params: { limit } }),
  getStockAnalysis: () => api.get('/mongo/admin/stock-analysis'),
  getProducts: () => api.get('/mongo/products'),
  createProduct: (productData) => api.post('/mongo/products', productData),
  updateProduct: (productId, productData) => api.put(`/mongo/products/${productId}`, productData),
  deleteProduct: (productId) => api.delete(`/mongo/products/${productId}`),
  getCustomerInsights: () => api.get('/mongo/admin/customer-insights'),
  getDailyMetrics: (startDate, endDate) => api.get('/mongo/admin/daily-metrics', { params: { startDate, endDate } }),
  getDashboard: () => api.get('/mongo/admin/dashboard'),
  getCategories: () => Promise.resolve({ data: [] })
};

export const addressAPI = {
  getAll: () => Promise.resolve({ data: [] }),
  add: (addressData) => Promise.resolve({ data: addressData }),
  remove: (addressId) => Promise.resolve({ data: { success: true } })
};

export const authAPI = {
  getProfile: () => {
    const userId = getUserIdFromToken();
    return Promise.resolve({ data: { id: userId, userId, fullName: '', email: '', mobile: '', gender: '', addresses: [] } });
  },
  updateProfile: (profileData) => Promise.resolve({ data: { success: true } })
};

export default api;
